1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	const COMPONENT_BASE_PER_ITEM = 25;
6	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
7	
8	const CURSED_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_YEARS_THRESHOLD = 2;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	
15	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	export function runScenario(input: unknown): unknown {
23	  const { customer, steps } = input as Scenario;
24	  const years = customer?.yearsWithMHPCO ?? 0;
25	  const premium = computePremium(steps[0].items, years);
26	  return { results: [{ premium }] };
27	}
28	
29	function computePremium(items: Item[], years: number): number {
30	  if (items.length === 0) return PROCESSING_FEE;
31	  if (items.every(isComponent)) return componentsPremium(items);
32	  return singleItemPremium(items[0], years);
33	}
34	
35	function singleItemPremium(item: Item, years: number): number {
36	  const base = BASE_PREMIUM_BY_TYPE[item.type];
37	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
38	  const highEnchSurcharge = isHighlyEnchanted(item) ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
39	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
40	  const loyaltyDiscount = years >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;
41	  return Math.ceil(base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup - loyaltyDiscount) + PROCESSING_FEE;
42	}
43	
44	function isHighlyEnchanted(item: Item): boolean {
45	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
46	}
47	
48	function componentsPremium(items: Item[]): number {
49	  const runes = items.filter((i) => i.type === "rune").length;
50	  const moonstones = items.filter((i) => i.type === "moonstone").length;
51	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
52	}
53	
54	function componentTypeBase(count: number): number {
55	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
56	}
57	
58	function isComponent(item: Item): boolean {
59	  return item.type === "rune" || item.type === "moonstone";
60	}
61	
62	function premiumFromBase(base: number): number {
63	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
64	}
